import { useEffect, useRef, useState } from "react";

const PANELS = [
  { id: 1, widthRatio: 297 / 2000, src: "data:image/webp;base64," },
  { id: 2, widthRatio: 449 / 2000, src: "data:image/webp;base64," },
  { id: 3, widthRatio: 452 / 2000, src: "data:image/webp;base64," },
  { id: 4, widthRatio: 447 / 2000, src: "data:image/webp;base64," },
  { id: 5, widthRatio: 289 / 2000, src: "data:image/webp;base64," },
];

const GAP_RATIO = 16 / 2000;
const ASPECT = 2000 / 696;
const RADIUS = "clamp(6px, 2vw, 20px)";

export default function SolarHero() {
  const [animStates, setAnimStates] = useState(PANELS.map(() => "idle"));
  const [activePanel, setActivePanel] = useState(null);
  const [hoveredPanel, setHoveredPanel] = useState(null);
  const animTimers = useRef([]);
  const cycleTimer = useRef(null);
  const lastPanel = useRef(null);

  const clearAll = () => {
    animTimers.current.forEach(clearTimeout);
    clearTimeout(cycleTimer.current);
  };

  const play = () => {
    clearAll();
    setAnimStates(PANELS.map(() => "idle"));
    setActivePanel(null);

    PANELS.forEach((_, i) => {
      const t1 = setTimeout(() => {
        setAnimStates((prev) => {
          const n = [...prev]; n[i] = "animating"; return n;
        });
        const t2 = setTimeout(() => {
          setAnimStates((prev) => {
            const n = [...prev]; n[i] = "done"; return n;
          });
        }, 550 + i * 80);
        animTimers.current.push(t2);
      }, i * 80);
      animTimers.current.push(t1);
    });
  };

  const startCycle = () => {
    const pick = () => {
      let next;
      do { next = Math.floor(Math.random() * PANELS.length); }
      while (next === lastPanel.current);
      lastPanel.current = next;
      setActivePanel(next);
      // Active for 1.8s, then 0.6s pause, then next
      cycleTimer.current = setTimeout(() => {
        setActivePanel(null);
        cycleTimer.current = setTimeout(pick, 600);
      }, 1800);
    };
    cycleTimer.current = setTimeout(pick, 1200);
  };

  useEffect(() => {
    const t = setTimeout(play, 100);
    const c = setTimeout(startCycle, 1400);
    return () => { clearAll(); clearTimeout(t); clearTimeout(c); };
  }, []);

  return (
    <div style={styles.page}>
      <style>{`
        @keyframes fromTop {
          0%   { opacity:0; transform:translateY(-115%) scaleY(0.82); }
          60%  { opacity:1; }
          100% { opacity:1; transform:translateY(0) scaleY(1); }
        }
        @keyframes fromBottom {
          0%   { opacity:0; transform:translateY(115%) scaleY(0.82); }
          60%  { opacity:1; }
          100% { opacity:1; transform:translateY(0) scaleY(1); }
        }
        @keyframes shimmerSweep {
          0%   { transform:translateX(-120%); }
          100% { transform:translateX(220%); }
        }
        @keyframes shimmerIdle {
          0%   { transform:translateX(-140%) skewX(-15deg); opacity:0; }
          40%  { opacity:1; }
          100% { transform:translateX(260%) skewX(-15deg); opacity:0; }
        }
        @keyframes floatUp {
          0%,100% { transform:translateY(0) scaleY(1); }
          50%     { transform:translateY(-4px) scaleY(1.008); }
        }
        @keyframes breatheScale {
          0%,100% { transform:scale(1); }
          50%     { transform:scale(1.018); }
        }
      `}</style>

      <div style={styles.hero}>
        {PANELS.map((panel, i) => {
          const isOdd = panel.id % 2 !== 0;
          const state = animStates[i];
          const highlight = activePanel === i || hoveredPanel === i;

          const panelStyle = {
            ...styles.panel,
            flexBasis: `${panel.widthRatio * 100}%`,
            borderRadius: RADIUS,
            ...(state === "idle" && {
              opacity: 0,
              transform: isOdd ? "translateY(-115%) scaleY(0.82)" : "translateY(115%) scaleY(0.82)",
            }),
            ...(state === "animating" && {
              animation: `${isOdd ? "fromTop" : "fromBottom"} 0.55s cubic-bezier(0.22,1,0.36,1) forwards`,
              borderRadius: RADIUS,
            }),
            ...(state === "done" && {
              opacity: 1,
              borderRadius: RADIUS,
              animation: highlight
                ? `breatheScale 1.4s ease infinite`
                : `floatUp ${2.8 + i * 0.35}s ease-in-out infinite`,
              zIndex: highlight ? 2 : 1,
              cursor: "pointer",
            }),
          };

          return (
            <div
              key={panel.id}
              style={panelStyle}
              onMouseEnter={() => setHoveredPanel(i)}
              onMouseLeave={() => setHoveredPanel(null)}
            >
              <img src={panel.src} alt="" style={styles.img} />
              <div style={{
                position: "absolute", inset: 0,
                borderRadius: RADIUS,
                overflow: "hidden",
                pointerEvents: "none",
              }}>
                {/* idle slow shimmer – always sweeps every ~6s */}
                <div style={{
                  position: "absolute", top: 0, bottom: 0, width: "40%",
                  background: "linear-gradient(110deg, transparent 10%, rgba(255,255,255,0.07) 50%, transparent 90%)",
                  animation: `shimmerIdle ${6 + i * 0.9}s ease-in-out infinite`,
                  animationDelay: `${i * 1.1}s`,
                }} />
                {/* bright shimmer when active */}
                {activePanel === i && (
                  <div style={{
                    position: "absolute", top: 0, bottom: 0, width: "55%",
                    background: "linear-gradient(110deg, transparent 20%, rgba(255,220,80,0.18) 50%, transparent 80%)",
                    animation: "shimmerSweep 1.2s ease infinite",
                  }} />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

const styles = {
  page: {
    width: "100%",
    background: "#fff",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    boxSizing: "border-box",
  },
  hero: {
    position: "relative",
    width: "100%",
    aspectRatio: `${ASPECT}`,
    background: "#fff",
    display: "flex",
    alignItems: "stretch",
    gap: `${GAP_RATIO * 100}%`,
    boxSizing: "border-box",
  },
  panel: {
    flex: "1 1 0",
    minWidth: 0,
    overflow: "hidden",
    position: "relative",
    cursor: "pointer",
  },
  img: {
    width: "100%",
    height: "100%",
    objectFit: "cover",
    display: "block",
    pointerEvents: "none",
    userSelect: "none",
    borderRadius: "inherit",
  }
};